import { useEffect, useState } from 'react';

import { listResource } from 'lib/http/resourceClient';

export default function useSelectOptions(path, labelBuilder, queryParams = {}) {
  const [options, setOptions] = useState([]);

  useEffect(() => {
    let mounted = true;
    async function fetchOptions() {
      try {
        const pageSize = 200;
        let page = 1;
        const data = [];

        while (true) {
          const response = await listResource(path, { page_size: pageSize, page, ...queryParams });
          if (Array.isArray(response)) {
            data.push(...response);
            break;
          }
          const pageItems = response.results || [];
          data.push(...pageItems);
          if (!response.next) break;
          page += 1;
          if (page > 100) break;
        }

        if (!mounted) return;
        setOptions(
          data.map((item) => ({
            value: item.id,
            label: labelBuilder ? labelBuilder(item) : item.name || item.title || item.username || String(item.id)
          }))
        );
      } catch {
        if (mounted) setOptions([]);
      }
    }
    fetchOptions();
    return () => {
      mounted = false;
    };
  }, [path, JSON.stringify(queryParams)]);

  return options;
}
